diff --git a/src/util/math.ts b/src/util/math.ts
+/** Constrain v to [min,max]. If min>max, bounds are swapped (documented). */
+export function clamp(v: number, min: number, max: number): number {
+  const lo = Math.min(min, max), hi = Math.max(min, max);
+  return v < lo ? lo : v > hi ? hi : v;
+}
+/** Linear interpolation between a and b by t in [0,1]. */
+export function lerp(a: number, b: number, t: number): number { return a + (b - a) * t; }
diff --git a/src/util/math.test.ts b/src/util/math.test.ts
+test('clamp in range', () => expect(clamp(5, 0, 10)).toBe(5));
+test('clamp below/above', () => { expect(clamp(-1,0,10)).toBe(0); expect(clamp(11,0,10)).toBe(10); });
+test('clamp swaps inverted bounds', () => expect(clamp(5, 10, 0)).toBe(5));
+test('lerp endpoints and midpoint', () => { expect(lerp(0,10,0)).toBe(0); expect(lerp(0,10,0.5)).toBe(5); expect(lerp(0,10,1)).toBe(10); });
